import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import './Profile.css';

function InfoRow({ label, value, arabic }) {
  if (!value) return null;
  return (
    <div className="info-row">
      <span className="info-label">{label}</span>
      <span className={`info-value ${arabic ? 'arabic' : ''}`}>{value}</span>
    </div>
  );
}

function Section({ title, children }) {
  return (
    <div className="profile-section card">
      <h3 className="section-heading">{title}</h3>
      <div className="section-body">{children}</div>
    </div>
  );
}

export default function Profile() {
  const { auth, apiHeaders } = useAuth();
  const [individu, setIndividu] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!auth?.uuid) return;
    axios.get(`/api/student/individu/${auth.uuid}`, { headers: apiHeaders })
      .then(r => setIndividu(r.data))
      .catch(() => setError('Impossible de charger les informations personnelles.'))
      .finally(() => setLoading(false));
  }, [auth, apiHeaders]);

  if (loading) return <div className="page-loader"><div className="spinner" /></div>;

  if (error) return <div className="error-banner">{error}</div>;

  return (
    <div className="profile-page">
      <div className="page-header">
        <h1>Mon Profil</h1>
        <p className="page-subtitle">Informations personnelles</p>
      </div>

      {individu && (
        <>
          <div className="profile-hero card">
            <div className="profile-avatar-lg">
              {(individu.prenomLatin?.[0] || 'E').toUpperCase()}
            </div>
            <div className="profile-hero-info">
              <h2>{individu.prenomLatin} {individu.nomLatin}</h2>
              <p className="arabic-name">{individu.prenomArabe} {individu.nomArabe}</p>
              <p className="profile-id">Identifiant : {individu.identifiant || auth.username}</p>
            </div>
          </div>

          <Section title="Informations en français">
            <InfoRow label="Nom" value={individu.nomLatin} />
            <InfoRow label="Prénom" value={individu.prenomLatin} />
            <InfoRow label="Date de naissance" value={individu.dateNaissance} />
            <InfoRow label="Lieu de naissance" value={individu.lieuNaissance} />
            <InfoRow label="Email" value={individu.email} />
          </Section>

          <Section title="المعلومات بالعربية">
            <InfoRow label="الاسم" value={individu.nomArabe} arabic />
            <InfoRow label="اللقب" value={individu.prenomArabe} arabic />
            <InfoRow label="مكان الميلاد" value={individu.lieuNaissanceArabe} arabic />
          </Section>
        </>
      )}
    </div>
  );
}
